// Extraer datos del payload del CRM
const body = $input.first().json.body || $input.first().json;
const provider = body.provider;
const leadName = body.lead_name || 'Cliente';
const leadPhone = body.lead_phone || body.phone || '—';
const pickupLocation = body.pickup_location || '—';
const returnLocation = body.return_location || '—';
const categoryName = body.category?.name || body.category_name || '—';
const balanceAtCounter = body.balance_at_counter || 0;

// Formatear fechas y horas en horario de Florida (America/New_York)
const pickupDateStr = body.pickup_date;
const returnDateStr = body.return_date;

const formatDateTime = (dateStr) => {
  if (!dateStr) return '—';
  const date = new Date(dateStr);
  const dateFormatted = date.toLocaleDateString('es-CO', { day: '2-digit', month: '2-digit', year: 'numeric', timeZone: 'America/New_York' });
  const timeFormatted = date.toLocaleTimeString('es-CO', { hour: '2-digit', minute: '2-digit', timeZone: 'America/New_York' });
  return `${dateFormatted} ${timeFormatted}`;
};

const pickupDateTime = formatDateTime(pickupDateStr);
const returnDateTime = formatDateTime(returnDateStr);

// Formatear valor a pagar en counter: $00.00 + Sun Pass + Taxes
const formattedBalance = `$${Number(balanceAtCounter).toFixed(2)} + Sun Pass + Taxes`;

const message = [
  '📋 *CONFIRMACIÓN DE RESERVA AL PROVEEDOR*',
  '',
  `Nombre del cliente: ${leadName}`,
  `Teléfono del cliente: ${leadPhone}`,
  `Lugar de llegada: ${pickupLocation}`,
  `Fecha y hora de llegada: ${pickupDateTime}`,
  `Lugar de devolución: ${returnLocation}`,
  `Fecha y hora de devolución: ${returnDateTime}`,
  `Tipo de vehículo: ${categoryName}`,
  `Valor a pagar en counter: ${formattedBalance}`,
].join('\n');

const whatsappGroupId = provider?.whatsapp_group_id;
const send = !!whatsappGroupId;

return [{ json: { send, whatsapp_group_id: whatsappGroupId, message } }];
